// Evolution e 360dialog hanno payload diversi. Qui li appiattiamo in un formato
// unico, così il resto del workflow non sa (e non deve sapere) chi è il provider.
// Quando si migra un cliente a 360dialog, si tocca SOLO questa funzione.

const out = [];

for (const item of $input.all()) {
  const b = item.json.body ?? item.json;
  let msg = null;

  // --- Evolution API (messages.upsert) ---
  if (b.event || b.data?.key) {
    const d = b.data ?? {};
    msg = {
      provider: 'evolution',
      numero_destinatario: d.key?.remoteJid ? String(b.instance ?? '') : '',
      numero_mittente: d.key?.remoteJid ?? '',
      da_me: Boolean(d.key?.fromMe),
      is_gruppo: String(d.key?.remoteJid ?? '').includes('@g.us'),
      testo: d.message?.conversation
        ?? d.message?.extendedTextMessage?.text
        ?? null,
      nome_contatto: d.pushName ?? null,
      message_id: d.key?.id ?? null,
      instance: b.instance ?? null,
    };
  }

  // --- 360dialog / WhatsApp Cloud API ---
  else if (b.entry) {
    const value = b.entry?.[0]?.changes?.[0]?.value ?? {};
    const m = value.messages?.[0];
    if (m) {
      msg = {
        provider: '360dialog',
        numero_destinatario: value.metadata?.display_phone_number ?? '',
        numero_mittente: m.from ?? '',
        da_me: false,
        is_gruppo: false,
        testo: m.text?.body ?? null,
        nome_contatto: value.contacts?.[0]?.profile?.name ?? null,
        message_id: m.id ?? null,
        instance: null,
      };
    }
  }

  if (!msg) continue;

  // Il numero su cui SIAMO NOI: è quello che identifica il cliente.
  // Evolution non lo mette sempre nel payload; in quel caso si usa l'instance,
  // che in config/clienti.json è mappata sul cliente.
  msg.chiave_tenant = msg.numero_destinatario || msg.instance || '';

  out.push({ json: msg });
}

return out;

// Vault e stato conversazione vengono dal backend: n8n non tiene copie di FAQ,
// orari o numeri. Se li tenesse, prima o poi risponderebbe con quelli vecchi.

const base = $vars.BACKEND_URL;
const headers = { 'X-API-Key': $vars.BACKEND_API_KEY };
const out = [];

for (const item of $input.all()) {
  const tenant = item.json.body;
  const msg = $('Normalizza payload').first().json;
  const cid = tenant.client_id;
  const telefono = String(msg.numero_mittente).split('@')[0];

  const vault = await this.helpers.httpRequest({
    method: 'GET', url: `${base}/${cid}/vault`, headers, json: true,
  });

  const conv = await this.helpers.httpRequest({
    method: 'GET', url: `${base}/${cid}/conversazione/${telefono}`, headers, json: true,
  });

  out.push({ json: {
    tenant,
    messaggio: msg,
    telefono,
    vault: vault.file,
    conversazione: conv.conversazione,
  }});
}

return out;

