// Tutta la logica di decisione sta QUI, in un posto solo, invece che sparsa in venti
// nodi grafici. Così è leggibile, e si può testare.

const ctx = $('Carica vault e conversazione').first().json;
const risposta = $input.first().json;
const soglia = ctx.tenant.soglia_confidenza ?? 0.6;

let intento = { intento: 'altro', confidenza: 0 };
try {
  if (risposta.statusCode !== 200) throw new Error('LLM ha risposto ' + risposta.statusCode);
  intento = JSON.parse(risposta.body.choices[0].message.content);
} catch (e) {
  // LLM giù o output non parsabile: NON si improvvisa, si passa all'umano.
  return [{ json: { ...ctx, azione: 'escalation', motivo: 'classificatore non disponibile: ' + e.message, intento } }];
}

const esclusi = ['reclamo', 'urgenza'];
let azione, motivo = null;

if (esclusi.includes(intento.intento)) {
  azione = 'escalation';
  motivo = `intento '${intento.intento}' — sempre gestito da un umano`;
} else if ((intento.confidenza ?? 0) < soglia) {
  azione = 'escalation';
  motivo = `confidenza ${intento.confidenza} sotto la soglia ${soglia}`;
} else if (['prenota', 'sposta', 'cancella', 'conferma'].includes(intento.intento)) {
  azione = 'calendario';
} else {
  azione = 'rispondi';
}

// Troppi giri senza risolvere: l'utente si sta stancando, passa all'umano.
const giri = (ctx.conversazione.stato?.giri ?? 0) + 1;
if (giri > 8 && azione !== 'escalation') {
  azione = 'escalation';
  motivo = `${giri} messaggi senza risolvere`;
}

return [{ json: { ...ctx, azione, motivo, intento, giri } }];

// 1. mette in pausa il bot per questo utente (e registra l'evento)
// 2. avvisa il titolare
// 3. dice al cliente che lo richiameranno — senza inventare risposte

const base = $vars.BACKEND_URL;
const headers = { 'X-API-Key': $vars.BACKEND_API_KEY };
const out = [];

for (const item of $input.all()) {
  const d = item.json;
  const cid = d.tenant.client_id;

  await this.helpers.httpRequest({
    method: 'POST',
    url: `${base}/${cid}/pausa-bot/${d.telefono}`,
    headers, json: true,
    body: { motivo: d.motivo ?? 'escalation' },
  });

  const avviso = [
    `ESCALATION — ${d.tenant.nome}`,
    `Cliente: ${d.messaggio.nome_contatto ?? 'sconosciuto'} (${d.telefono})`,
    `Motivo: ${d.motivo}`,
    `Messaggio: "${d.messaggio.testo}"`,
    '',
    'Il bot NON risponde più a questo utente finché non lo riattivi.',
  ].join('\n');

  out.push({ json: {
    ...d,
    avviso_titolare: avviso,
    destinatario_avviso: d.tenant.escalation?.whatsapp ?? null,
    risposta: 'Su questo la faccio ricontattare direttamente da un collega, così le diamo la risposta giusta. A presto.',
  }});
}

return out;

// Prenota / sposta / cancella / conferma. Regola d'oro: si conferma al cliente SOLO
// dopo che il backend ha risposto OK. Mai prima.

const base = $vars.BACKEND_URL;
const headers = { 'X-API-Key': $vars.BACKEND_API_KEY };
const out = [];

const ora = (iso) => iso.slice(11, 16);
const giorno = (iso) => new Date(iso).toLocaleDateString('it-IT', { weekday: 'long', day: 'numeric', month: 'long' });

for (const item of $input.all()) {
  const d = item.json;
  const cid = d.tenant.client_id;
  const stato = d.conversazione.stato ?? {};
  let risposta, nuovoStato = { ...stato, giri: d.giri };

  try {
    // --- il cliente accetta uno slot che gli abbiamo proposto ---
    if (d.intento.intento === 'conferma' && stato.slot_proposti?.length) {
      const scelto = stato.slot_proposti[0];
      const p = await this.helpers.httpRequest({
        method: 'POST', url: `${base}/${cid}/prenota`, headers, json: true,
        body: {
          servizio: stato.servizio ?? 'appuntamento',
          nome_cliente: stato.nome ?? d.messaggio.nome_contatto ?? 'Cliente',
          telefono: d.telefono,
          inizio: scelto,
          durata_min: stato.durata_min ?? undefined,
        },
      });
      risposta = `Perfetto, confermato per ${giorno(scelto)} alle ${ora(scelto)}. A presto.`;
      nuovoStato = { giri: d.giri, ultima_prenotazione: p.prenotazione.id };
    }

    // --- il cliente chiede un appuntamento: proponiamo gli slot ---
    else if (d.intento.intento === 'prenota') {
      const oggi = new Date().toISOString().slice(0, 10);
      const da = d.intento.data ?? oggi;
      const disp = await this.helpers.httpRequest({
        method: 'GET', url: `${base}/${cid}/disponibilita`, headers, json: true,
        qs: { da, a: d.intento.data ?? undefined, limite: 3 },
      });

      if (!disp.slot.length) {
        risposta = 'Per quel giorno non ho più posto. Vuole che le proponga la prima data utile?';
        nuovoStato = { ...nuovoStato, fase: 'nessuno_slot' };
      } else {
        const proposte = disp.slot.map((s) => `${giorno(s.inizio)} alle ${ora(s.inizio)}`);
        risposta = disp.slot.length === 1
          ? `Ho libero ${proposte[0]}. Le va bene?`
          : `Ho libero: ${proposte.join(', ')}. Quale preferisce?`;
        nuovoStato = {
          ...nuovoStato,
          fase: 'attesa_conferma',
          slot_proposti: disp.slot.map((s) => s.inizio),
          servizio: d.intento.servizio ?? null,
          nome: d.intento.nome ?? null,
        };
      }
    }

    // --- disdetta ---
    else if (d.intento.intento === 'cancella') {
      const lista = await this.helpers.httpRequest({
        method: 'GET', url: `${base}/${cid}/prenotazioni`, headers, json: true,
        qs: { da: new Date().toISOString().slice(0, 10) },
      });
      const mie = lista.prenotazioni.filter((p) => p.telefono === d.telefono);
      if (!mie.length) {
        risposta = 'Non trovo appuntamenti a suo nome. Vuole che glielo fissi?';
      } else {
        await this.helpers.httpRequest({
          method: 'POST', url: `${base}/${cid}/cancella`, headers, json: true,
          body: { prenotazione_id: mie[0].id },
        });
        risposta = `Ho cancellato l'appuntamento di ${giorno(mie[0].inizio)} alle ${ora(mie[0].inizio)}. Quando vuole riprenotare mi scriva pure.`;
        nuovoStato = { giri: d.giri };
      }
    }

    // --- spostamento: richiede un umano finché non lo gestiamo bene ---
    else {
      return [{ json: { ...d, azione: 'escalation', motivo: 'spostamento appuntamento', risposta: 'Le faccio risistemare l\'appuntamento da un collega, la ricontattiamo a breve.' } }];
    }
  } catch (e) {
    // Calendario giù o slot rubato nel frattempo: NON si conferma niente.
    return [{ json: { ...d, azione: 'escalation', motivo: 'calendario in errore: ' + e.message, risposta: 'Sto verificando sull\'agenda, le confermo io tra poco.' } }];
  }

  out.push({ json: { ...d, risposta, nuovo_stato: nuovoStato } });
}

return out;

