// Punto di raccolta dei tre rami. Salva lo stato, calcola il ritardo, prepara il testo.

const base = $vars.BACKEND_URL;
const headers = { 'X-API-Key': $vars.BACKEND_API_KEY };
const out = [];

for (const item of $input.all()) {
  const d = item.json;
  const cid = d.tenant?.client_id ?? $('Decidi cosa fare').first().json.tenant.client_id;
  const ctx = d.tenant ? d : $('Decidi cosa fare').first().json;

  // Risposta: dal ramo calendario/escalation, oppure dall'LLM del ramo 'rispondi'
  let testo = d.risposta;
  if (!testo && d.body?.choices) testo = d.body.choices[0].message.content.trim();
  if (!testo) testo = 'Le faccio sapere a breve.';

  // Ritardo casuale 5-15 min: sembrare umani, e non farsi bannare da Meta.
  const { min, max } = ctx.tenant.delay_risposta_sec ?? { min: 300, max: 900 };
  const attesa = Math.floor(min + Math.random() * (max - min));

  // Lo stato NON riattiva un bot in pausa (ci pensa il backend).
  if (d.azione !== 'escalation') {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${base}/${cid}/conversazione/${ctx.telefono}`,
      headers, json: true,
      body: { stato: d.nuovo_stato ?? { giri: ctx.giri ?? 1 } },
    });
  }

  await this.helpers.httpRequest({
    method: 'POST', url: `${base}/${cid}/eventi`, headers, json: true,
    body: {
      tipo: 'messaggio_gestito',
      telefono: ctx.telefono,
      dati: {
        intento: ctx.intento?.intento ?? null,
        confidenza: ctx.intento?.confidenza ?? null,
        azione: d.azione ?? ctx.azione,
        in_arrivo: ctx.messaggio.testo,
        risposta: testo,
      },
    },
  });

  out.push({ json: {
    client_id: cid,
    provider: ctx.tenant.provider_whatsapp,
    instance: ctx.tenant.instance,
    telefono: ctx.telefono,
    testo,
    attesa_sec: attesa,
    avviso_titolare: d.avviso_titolare ?? null,
    destinatario_avviso: d.destinatario_avviso ?? null,
  }});
}

return out;
